import { GoldRushClient } from "@covalenthq/client-sdk";

// Lightweight wrapper that counts credits consumed
class BudgetedClient {
  constructor(apiKey, maxCredits = 1000) {
    this.client = new GoldRushClient(apiKey);
    this.maxCredits = maxCredits;
    this.used = 0;
  }

  async call(service, method, ...args) {
    if (this.used >= this.maxCredits) throw new Error("Credit budget exhausted");
    this.used += 1;
    return this.client[service][method](...args);
  }

  budget() {
    return { used: this.used, remaining: this.maxCredits - this.used };
  }
}
